import stylesText from './food-thumbnail.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';
import { FilesService } from '../../../services/files.service.js';

const styles = cssStyleSheet(stylesText);

const PLACEHOLDER_SVG = `
<svg viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
    <circle cx="12" cy="12" r="9" stroke="currentColor" stroke-width="1.5" opacity="0.4"></circle>
    <circle cx="12" cy="12" r="4.5" stroke="currentColor" stroke-width="1.5" opacity="0.4"></circle>
</svg>
`.trim();

const PENDING_SVG = `
<svg class="spinner" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
    <circle cx="12" cy="12" r="9" stroke="currentColor" stroke-width="1.5" opacity="0.2"></circle>
    <path d="M12 3a9 9 0 0 1 9 9" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"></path>
</svg>
`.trim();

const template = document.createElement('template');
template.innerHTML = `
    <div class="thumb" part="thumb">
        <img class="thumb-img" alt="" loading="lazy" decoding="async" hidden>
        <span class="placeholder" hidden>${PLACEHOLDER_SVG}</span>
        <span class="pending-spinner" hidden>${PENDING_SVG}</span>
    </div>
`;

/**
 * Shared row-thumbnail element. Story 125.
 *
 * Three rendering modes:
 *   <food-thumb path="images/food/<uuidv7>"></food-thumb>
 *   <food-thumb remote="https://off/img.jpg"></food-thumb>
 *   <food-thumb></food-thumb>                          (placeholder glyph)
 *
 * Size is controlled by the consumer via the `--food-thumb-size` CSS custom
 * property (default 48px). The element renders a square; the inner <img>
 * uses object-fit: cover.
 *
 * The element owns the URL composition rule for served images — callers
 * never construct /api/files/... URLs themselves. This keeps the variant
 * choice (`display.jpg`) in one place so a future thumb variant is a
 * one-line change here.
 */
export class FoodThumbnail extends HTMLElement {
    static get observedAttributes() { return ['path', 'remote', 'alt']; }

    private pathValue: string | null = null;
    private remoteValue: string | null = null;
    private altValue = '';

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
    }

    attributeChangedCallback(name: string, _oldValue: string | null, newValue: string | null): void {
        if (name === 'path') {
            this.pathValue = newValue && newValue.trim() ? newValue.trim() : null;
        } else if (name === 'remote') {
            this.remoteValue = newValue && newValue.trim() ? newValue.trim() : null;
        } else if (name === 'alt') {
            this.altValue = newValue ?? '';
        }
        this.render();
    }

    connectedCallback(): void {
        this.render();
    }

    private render(): void {
        const shadow = this.shadowRoot;
        if (!shadow) return;
        const img = shadow.querySelector('.thumb-img') as HTMLImageElement;
        const placeholder = shadow.querySelector('.placeholder') as HTMLElement;
        const pending = shadow.querySelector('.pending-spinner') as HTMLElement;

        if (pending) pending.hidden = true;

        if (this.pathValue) {
            if (this.pathValue.startsWith('pending:')) {
                img.removeAttribute('src');
                img.hidden = true;
                placeholder.hidden = true;
                if (pending) pending.hidden = false;
                return;
            }
            img.src = FilesService.variantUrl(this.pathValue, 'display.jpg');
            img.alt = this.altValue;
            img.hidden = false;
            placeholder.hidden = true;
            return;
        }
        if (this.remoteValue) {
            // CORS request so the response satisfies COEP `require-corp` via
            // Access-Control-Allow-Origin (OFF's CDN doesn't send CORP).
            img.crossOrigin = 'anonymous';
            img.src = this.remoteValue;
            img.alt = this.altValue;
            img.hidden = false;
            placeholder.hidden = true;
            return;
        }
        img.removeAttribute('src');
        img.hidden = true;
        placeholder.hidden = false;
    }
}

customElements.define('food-thumb', FoodThumbnail);
